import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { toast } from "react-toastify";

function TeacherCourses() {
  const [courses, setCourses] = useState([]);
  const [files, setFiles] = useState([]);
  const user = useSelector((state) => state.auth.user);

  useEffect(() => {
    fetch(`http://localhost:3001/courses?teacherId=${user.id}`)
      .then((res) => res.json())
      .then((data) => setCourses(data))
      .catch((error) => toast.error("Ошибка загрузки курсов"));
    fetch(`http://localhost:3001/files`)
      .then((res) => res.json())
      .then((data) => setFiles(data))
      .catch((error) => toast.error("Ошибка загрузки файлов"));
  }, [user.id]);

  if (user?.role !== "teacher") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  const isImage = (fileName) => /\.(jpg|jpeg|png)$/i.test(fileName);

  return (
    <div className="container mt-5">
      <h1 className="mb-4">Мои курсы</h1>
      {courses.length === 0 ? (
        <p className="text-muted">У вас нет курсов.</p>
      ) : (
        <ul className="list-group">
          {courses.map((course) => (
            <li key={course.id} className="list-group-item">
              <h3>{course.name}</h3>
              <p><strong>Класс:</strong> {course.classId}</p>
              <p><strong>Дедлайн:</strong> {course.deadline}</p>
              <h5>Файлы:</h5>
              {files.filter((f) => f.courseId === course.id).length === 0 ? (
                <p>Нет файлов.</p>
              ) : (
                <ul className="list-group">
                  {files
                    .filter((f) => f.courseId === course.id)
                    .map((f) => (
                      <li key={f.id} className="list-group-item d-flex align-items-center gap-2">
                        {isImage(f.fileName) ? (
                          <img
                            src={`http://localhost:3002${f.filePath}`}
                            alt={f.fileName}
                            className="img-thumbnail"
                            style={{ width: "100px", height: "100px" }}
                          />
                        ) : (
                          <a
                            href={`http://localhost:3002${f.filePath}`}
                            download
                            className="text-primary"
                          >
                            {f.fileName}
                          </a>
                        )}
                      </li>
                    ))}
                </ul>
              )}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default TeacherCourses;
